import React, { useState } from "react";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

function Home() {
  const Header = () => {
    const [location, setLocation] = useState("");
    const [checkIn, setCheckIn] = useState(null);
    const [checkOut, setCheckOut] = useState(null);
    const [guests, setGuests] = useState(1);

    const handleSearch = () => {
      if (!location.trim()) {
        alert("Please enter a location.");
        return;
      }
      if (!checkIn || !checkOut) {
        alert("Please select check-in and check-out dates.");
        return;
      }
      if (guests < 1) {
        alert("Please enter a valid number of guests.");
        return;
      }

      alert(
        `Searching for ${location}\nCheck-in: ${checkIn.toLocaleDateString()}\nCheck-out: ${checkOut.toLocaleDateString()}\nGuests: ${guests}`
      );
    };

    const commonInputStyle = {
      height: "42px",
      padding: "0 14px",
      fontSize: "16px",
      borderRadius: "8px",
      border: "1.8px solid #c35050ff",
      outline: "none",
      transition: "border-color 0.3s ease",
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
      boxShadow: "0 1px 3px rgba(106, 167, 129, 0.1)",
    };

    const inputFocusStyle = {
      borderColor: "#FF385C",
      boxShadow: "0 0 6px #FF385C",
    };

    // We'll track focus state for inputs to add focus styles
    const [focusInput, setFocusInput] = useState(null);

    return (
      <header
        style={{
          padding: "20px 30px",
          backgroundColor: "#ffffffff",
          boxShadow: "0 2px 12px rgba(0,0,0,0.1)",
          position: "sticky",
          top: 0,
          zIndex: 100,
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          alignItems: "center",
          gap: "15px",
        }}
      >
        <h1
          style={{
            color: "#FF385C",
            fontWeight: "900",
            fontSize: "2.2rem",
            flexBasis: "100%",
            textAlign: "center",
            marginBottom: "10px",
            userSelect: "none",
            fontFamily: "'Trebuchet MS', Helvetica, sans-serif",
          }}
        >
          Airbnb
        </h1>

        <input
          type="text"
          placeholder="Where are you going?"
          value={location}
          onChange={(e) => setLocation(e.target.value)}
          onFocus={() => setFocusInput("location")}
          onBlur={() => setFocusInput(null)}
          style={{
            ...commonInputStyle,
            width: "220px",
            borderColor: focusInput === "location" ? inputFocusStyle.borderColor : commonInputStyle.border,
            boxShadow: focusInput === "location" ? inputFocusStyle.boxShadow : commonInputStyle.boxShadow,
          }}
        />

        <DatePicker
          selected={checkIn}
          onChange={(date) => setCheckIn(date)}
          selectsStart
          startDate={checkIn}
          endDate={checkOut}
          placeholderText="Check-in"
          onFocus={() => setFocusInput("checkIn")}
          onBlur={() => setFocusInput(null)}
          customInput={
            <input
              style={{
                ...commonInputStyle,
                width: "150px",
                borderColor: focusInput === "checkIn" ? inputFocusStyle.borderColor : commonInputStyle.border,
                boxShadow: focusInput === "checkIn" ? inputFocusStyle.boxShadow : commonInputStyle.boxShadow,
                cursor: "pointer",
              }}
              readOnly
            />
          }
        />

        <DatePicker
          selected={checkOut}
          onChange={(date) => setCheckOut(date)}
          selectsEnd
          startDate={checkIn}
          endDate={checkOut}
          minDate={checkIn}
          placeholderText="Check-out"
          onFocus={() => setFocusInput("checkOut")}
          onBlur={() => setFocusInput(null)}
          customInput={
            <input
              style={{
                ...commonInputStyle,
                width: "150px",
                borderColor: focusInput === "checkOut" ? inputFocusStyle.borderColor : commonInputStyle.border,
                boxShadow: focusInput === "checkOut" ? inputFocusStyle.boxShadow : commonInputStyle.boxShadow,
                cursor: "pointer",
              }}
              readOnly
            />
          }
        />

        <input
          type="number"
          min="1"
          value={guests}
          onChange={(e) => setGuests(Number(e.target.value))}
          placeholder="Guests"
          onFocus={() => setFocusInput("guests")}
          onBlur={() => setFocusInput(null)}
          style={{
            ...commonInputStyle,
            width: "100px",
            borderColor: focusInput === "guests" ? inputFocusStyle.borderColor : commonInputStyle.border,
            boxShadow: focusInput === "guests" ? inputFocusStyle.boxShadow : commonInputStyle.boxShadow,
          }}
        />

        <button
          onClick={handleSearch}
          style={{
            padding: "12px 30px",
            backgroundColor: "#d85167ff",
            color: "white",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
            fontWeight: "700",
            fontSize: "16px",
            boxShadow: "0 4px 10px rgba(255,56,92,0.4)",
            transition: "background-color 0.3s ease, box-shadow 0.3s ease",
            flexShrink: 0,
          }}
          onMouseEnter={(e) => {
            e.target.style.backgroundColor = "#e22f54";
            e.target.style.boxShadow = "0 6px 14px rgba(226,47,84,0.6)";
          }}
          onMouseLeave={(e) => {
            e.target.style.backgroundColor = "#FF385C";
            e.target.style.boxShadow = "0 4px 10px rgba(255,56,92,0.4)";
          }}
        >
          Search
        </button>
      </header>
    );
  };

  return (
    <div style={{ fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif" }}>
      <Header />
      <div
        style={{
          backgroundImage:
            "url('https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?fit=crop&w=1200')",
          height: "90vh",
          backgroundSize: "cover",
          backgroundPosition: "center",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          color: "white",
          textShadow: "3px 3px 10px rgba(0,0,0,0.85)",
          fontSize: "3.5rem",
          fontWeight: "900",
          marginTop: "20px",
          userSelect: "none",
          padding: "0 20px",
          textAlign: "center",
        }}
      >
        Welcome to Airbnb 🏠
      </div>
    </div>
  );
}

export default Home;
